tools.handler:
var clientId = getVar('youtube_client_id');
var clientSecret = getVar('youtube_client_secret');
var refreshToken = getVar('youtube_refresh_token');

if (!clientId || !clientSecret || !refreshToken) {
  return JSON.stringify({error: 'YouTube OAuth2 credentials not configured. Set youtube_client_id, youtube_client_secret, and youtube_refresh_token variables.'});
}

var body = 'client_id=' + encodeURIComponent(clientId)
  + '&client_secret=' + encodeURIComponent(clientSecret)
  + '&refresh_token=' + encodeURIComponent(refreshToken)
  + '&grant_type=refresh_token';

var resp = httpPost('https://oauth2.googleapis.com/token', body, {
  'Content-Type': 'application/x-www-form-urlencoded'
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Token refresh failed (HTTP ' + resp.status + '): ' + errBody + '. You may need to re-authorize YouTube access.'});
}

var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;

return JSON.stringify({
  access_token: data.access_token,
  token_type: data.token_type,
  expires_in: data.expires_in
}, null, 2);
